@page "/privacy"
@using Microsoft.AspNetCore.Components.Routing
@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success" role="alert">
        ✔ You have already accepted the cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        You have not yet accepted the cookie policy.
    </div>
}

<p>
    This page describes how the application collects, uses, and shares your
    personal data. Because it needs to inspect cookies from the incoming HTTP
    request, it renders using static server-side rendering even though the rest
    of the application uses interactive server rendering.
</p>

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private bool HasConsented =>
        HttpContext?.Request.Cookies.ContainsKey("consent") == true;
}

